// migrate is a standalone CLI tool for managing database schema migrations.
// It must be run manually against the production database whenever the schema changes.
//
// Usage:
//
//	go run ./cmd/migrate [up|down|status]
//
// Commands:
//
//	up      Apply all pending migrations (default when no command is given)
//	down    Roll back the last migration group
//	status  Print the list of applied and pending migrations
package main

import (
	"context"
	"fmt"
	"log/slog"
	"os"

	"github.com/AlexL70/linkshortener/backend/config"
	"github.com/AlexL70/linkshortener/backend/infrastructure/pg"
	"github.com/AlexL70/linkshortener/backend/infrastructure/pg/migrations"
	"github.com/uptrace/bun/migrate"
)

func main() {
	slog.SetDefault(slog.New(slog.NewJSONHandler(os.Stdout, nil)))

	if err := config.LoadEnv(); err != nil {
		slog.Error("failed to load environment", "error", err)
		os.Exit(1)
	}

	db, err := pg.Open()
	if err != nil {
		slog.Error("failed to open database", "error", err)
		os.Exit(1)
	}
	defer db.Close() // nolint: errcheck — best-effort close on exit

	migrator := migrate.NewMigrator(db, migrations.Migrations)

	ctx := context.Background()
	if err := migrator.Init(ctx); err != nil {
		slog.Error("failed to initialise migrator", "error", err)
		os.Exit(1)
	}

	cmd := "up"
	if len(os.Args) > 1 {
		cmd = os.Args[1]
	}

	switch cmd {
	case "up":
		group, err := migrator.Migrate(ctx)
		if err != nil {
			slog.Error("migration up failed", "error", err)
			os.Exit(1)
		}
		if group.IsZero() {
			slog.Info("already up to date — no migrations applied")
		} else {
			slog.Info("migrations applied", "group", group.String())
		}

	case "down":
		group, err := migrator.Rollback(ctx)
		if err != nil {
			slog.Error("migration down failed", "error", err)
			os.Exit(1)
		}
		if group.IsZero() {
			slog.Info("nothing to roll back")
		} else {
			slog.Info("migration rolled back", "group", group.String())
		}

	case "status":
		ms, err := migrator.MigrationsWithStatus(ctx)
		if err != nil {
			slog.Error("failed to get migration status", "error", err)
			os.Exit(1)
		}
		for _, m := range ms {
			fmt.Printf("%-6s  %s\n", m.Status(), m.Name)
		}

	default:
		fmt.Fprintf(os.Stderr, "unknown command %q — use: up | down | status\n", cmd)
		os.Exit(1)
	}
}

// migrate is a standalone CLI tool for managing database schema migrations.
// It must be run manually against the production database whenever the schema changes.
//
// Usage:
//
//	go run ./cmd/migrate [up|down|status]
//
// Commands:
//
//	up      Apply all pending migrations (default when no command is given)
//	down    Roll back the last migration group
//	status  Print the list of applied and pending migrations
