\t\t\tos.Exit(1)
\t\t}
\t}

\tif err := writeFullSchema(*outDir, date); err != nil {
\t\tfmt.Fprintf(os.Stderr, "gensql: write schema.sql: %v\\n", err)
\t\tos.Exit(1)
\t}

\tfmt.Printf("gensql: wrote %d migration file(s) to %s/\\n", len(migrations.SQLScripts), *outDir)
}

