func writeMigration(outDir string, script migrations.SQLScript, date string) error {
\tpath := filepath.Join(outDir, script.Name+".sql")
\tf, err := os.Create(path)
\tif err != nil {
\t\treturn fmt.Errorf("create %s: %w", path, err)
\t}
\tdefer f.Close() //nolint:errcheck -- write-only file, errors are surfaced above

\tfmt.Fprintf(f, "-- Migration: %s\\n", script.Name)
\tfmt.Fprintf(f, "-- Generated: %s\\n", date)
\tfmt.Fprintf(f, "-- Apply with: psql \\"$DATABASE_URL\\" -f sql/%s.sql\\n", script.Name)
\tfmt.Fprintln(f)
\tfmt.Fprintln(f, "BEGIN;")
