\t\tfmt.Fprintf(f, "\\n%s;\\n", strings.TrimRight(strings.TrimSpace(stmt), ";"))
\t}
\tfmt.Fprintln(f)
\tfmt.Fprintln(f, "COMMIT;")
\treturn nil
}

// writeFullSchema writes all migrations in order to <outDir>/schema.sql.
